import React, { useState } from 'react';
import { User, Activity, Globe, TrendingUp, ArrowLeft, Search, X, ChevronRight, BarChart3, Zap, CreditCard, Check, Download, Star } from 'lucide-react';
import { AnalysisResult } from '../types';

interface DashboardProps {
  onBack: () => void;
  history: AnalysisResult[];
  onView: (analysis: AnalysisResult) => void;
}

// Sub-component for the Prediction Chart
const PredictionChart: React.FC<{ hostname: string; baseScore: number }> = ({ hostname, baseScore }) => {
  return (
    <div className="bg-black/40 rounded-xl p-6 border border-white/5 mt-4 animate-in fade-in slide-in-from-top-4 duration-500">
      <div className="flex justify-between items-end mb-6">
        <div>
          <h4 className="text-lg font-serif font-bold text-white mb-1">Projection de Visibilité IA</h4>
          <p className="text-xs text-gray-400">Simulation sur 6 mois basée sur le score actuel ({baseScore}/100)</p>
