        <div className="flex gap-4 text-xs">
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-gray-600"></div>
            <span className="text-gray-400">SEO Classique</span>
          </div>
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-primary shadow-[0_0_8px_rgba(16,185,129,0.5)]"></div>
            <span className="text-primary font-medium">Avec CitedBy</span>
          </div>
        </div>
      </div>

      <div className="relative h-64 w-full bg-gradient-to-b from-white/5 to-transparent rounded-lg border border-white/10 p-4 overflow-hidden">
        {/* Grid Lines */}
        <div className="absolute inset-0 flex flex-col justify-between p-4 opacity-10 pointer-events-none">
