        <div className="absolute inset-0 bg-primary/20 blur-3xl rounded-full opacity-20 -z-10"></div>
        <form onSubmit={handleSubmit}>
          <div className="flex items-center p-2 bg-white/5 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl transition-all focus-within:border-primary/50 focus-within:bg-white/10 focus-within:ring-1 focus-within:ring-primary/20">
            <Search className="text-gray-400 ml-4 shrink-0" size={24} />
            <input 
              type="url" 
              required
              placeholder="https://votre-site.com" 
              className="w-full bg-transparent border-none focus:ring-0 text-white placeholder-gray-500 text-lg px-4 py-4"
              value={inputUrl}
              onChange={(e) => setInputUrl(e.target.value)}
              autoFocus
            />
            <button 
              type="submit" 
              disabled={isAnalyzing}
              className={`px-8 py-4 rounded-xl font-semibold text-black transition-all transform hover:scale-105 shrink-0 ${isAnalyzing ? 'bg-gray-500 cursor-not-allowed' : 'bg-primary hover:bg-primaryDark shadow-lg shadow-primary/20'}`}
            >
              {isAnalyzing ? 'Analyse...' : 'Lancer l\'audit'}
            </button>
          </div>
        </form>

        <div className="flex justify-center gap-8 mt-8 text-sm text-gray-500">
          <span className="flex items-center gap-2"><ShieldCheck size={16} className="text-emerald-500"/> Analyse Sécurisée</span>
          <span className="flex items-center gap-2"><TrendingUp size={16} className="text-accent"/> +50 Critères GEO</span>
        </div>
      </div>

    </div>
  );
};

