import React, { useState } from 'react';
import { AnalysisResult, CategoryScore, Recommendation, GeneratedSolution, User } from '../types';
import { generateSolution } from '../services/generator';
import ScoreRing from '../components/ScoreRing';
import CategoryCard from '../components/CategoryCard';
import RecommendationCard from '../components/RecommendationCard';
import AICitationPreview from '../components/AICitationPreview';
import GenerationModal from '../components/GenerationModal';
import { ArrowLeft, Download, Share2, Loader2, Check, TrendingUp, Info, Zap, Lock } from 'lucide-react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface Props {
  data: AnalysisResult;
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
}

const Results: React.FC<Props> = ({ data, onBack, user, onDeductCredits }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'details' | 'recommendations' | 'preview'>('overview');
  const [processingAction, setProcessingAction] = useState<'idle' | 'download' | 'share'>('idle');
  const [showShareToast, setShowShareToast] = useState(false);

  // Generation Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isGeneratingSolution, setIsGeneratingSolution] = useState(false);
  const [generatedSolution, setGeneratedSolution] = useState<GeneratedSolution | null>(null);

  const tabs = [
    { id: 'overview', label: 'Vue d\'ensemble' },
    { id: 'details', label: 'Détails' },
    { id: 'recommendations', label: 'Plan d\'action' },
    { id: 'preview', label: 'Simulation IA' },
  ];

  const categoryScores = Object.values(data.categories) as CategoryScore[];
  const SOLUTION_COST = 5;

  const handleApplyRecommendation = async (rec: Recommendation) => {
    console.log("Action triggered for:", rec.id);

    // Check login
    if (!user) {
      alert("Veuillez vous connecter pour utiliser cette fonctionnalité.");
      return;
    }

    // Check credits
    if (user.credits < SOLUTION_COST) {
      alert(`Solde insuffisant (${user.credits}). Cette action nécessite ${SOLUTION_COST} crédits.`);
      return;
    }

    // Deduct credits directly (Action is user initiated)
    const success = onDeductCredits(SOLUTION_COST);
    if (!success) {
      alert("Erreur lors de la transaction de crédits.");
      return;
    }

    // OPEN MODAL IMMEDIATELY to show feedback
    setIsModalOpen(true);
    setIsGeneratingSolution(true);
    setGeneratedSolution(null);

    try {
      console.log("Generating solution...");
      const solution = await generateSolution(rec, data.url);
      console.log("Solution generated:", solution);
      setGeneratedSolution(solution);
    } catch (error) {
      console.error("Error generating solution", error);
      // Fallback in case of critical error
      setGeneratedSolution({
        title: "Erreur de génération",
        explanation: "Le service d'IA est momentanément indisponible.",
        type: 'text',
        content: "Veuillez réessayer dans quelques instants. Vos crédits n'ont pas été perdus (simulation).",
        implementationSteps: ["Vérifiez votre connexion internet", "Réessayez l'opération"]
      });
    } finally {
      setIsGeneratingSolution(false);
    }
  };

  const generatePdfBlob = async (): Promise<Blob | null> => {
    // Allow React to render the hidden div and assets to load
    await new Promise(resolve => setTimeout(resolve, 500));

    const input = document.getElementById('pdf-report-content');
    if (!input) return null;

    try {
        const canvas = await html2canvas(input, {
          scale: 2,
          useCORS: true,
          backgroundColor: '#0a0a0f',
          logging: false
        });

        const imgData = canvas.toDataURL('image/png');
        const pdf = new jsPDF({
          orientation: 'p',
          unit: 'mm',
          format: 'a4'
        });

        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();
        const imgProps = pdf.getImageProperties(imgData);
        const imgHeight = (imgProps.height * pdfWidth) / imgProps.width;

        let heightLeft = imgHeight;
        let position = 0;

        pdf.addImage(imgData, 'PNG', 0, position, pdfWidth, imgHeight);
        heightLeft -= pdfHeight;

        while (heightLeft > 0) {
            position = heightLeft - imgHeight;
            pdf.addPage();
            pdf.addImage(imgData, 'PNG', 0, position, pdfWidth, imgHeight);
            heightLeft -= pdfHeight;
        }

        return pdf.output('blob');
    } catch (err) {
        console.error('PDF Generation failed', err);
        return null;
    }
  };

  const handleDownloadPDF = async () => {
    setProcessingAction('download');
    const blob = await generatePdfBlob();
    if (blob) {
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `citedby-report-${new URL(data.url).hostname}.pdf`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    } else {
        alert("Une erreur est survenue lors de la génération du PDF.");
    }
    setProcessingAction('idle');
  };

  const copyToClipboard = async (text: string) => {
      try {
        await navigator.clipboard.writeText(text);
        setShowShareToast(true);
        setTimeout(() => setShowShareToast(false), 3000);
      } catch (err) {
        console.error('Failed to copy', err);
        alert('Impossible de copier le lien. Veuillez le copier manuellement depuis la barre d\'adresse.');
      }
  };

  const handleShare = async () => {
    const hostname = new URL(data.url).hostname;
    const shareData = {
      title: `CitedBy.ai - Analyse AEO pour ${hostname}`,
      text: `Mon site ${hostname} a obtenu un score AEO de ${data.globalScore}/100 sur CitedBy.ai. Optimisez votre visibilité pour l'ère de l'IA !`,
      url: window.location.href
    };

    if (!navigator.share) {
       copyToClipboard(`${shareData.text} ${shareData.url}`);
       return;
    }

    setProcessingAction('share');

    let fileShared = false;

    if (navigator.canShare) {
        try {
            const blob = await generatePdfBlob();
            if (blob) {
                const file = new File([blob], `citedby-report-${hostname}.pdf`, { type: 'application/pdf' });
                const fileShareData = {
                    files: [file],
                    title: shareData.title,
                    text: shareData.text
                };

                if (navigator.canShare(fileShareData)) {
                    await navigator.share(fileShareData);
                    fileShared = true;
                }
            }
        } catch (error) {
            console.warn("File sharing failed or cancelled", error);
            if (error instanceof Error && error.name === 'AbortError') {
                 setProcessingAction('idle');
                 return;
            }
        }
    }

    if (!fileShared) {
        try {
            await navigator.share(shareData);
        } catch (error) {
            console.warn("Text share failed or cancelled", error);
        }
    }

    setProcessingAction('idle');
  };

  return (
    <div className="max-w-6xl mx-auto px-4 pb-20 pt-6 relative">

      {/* Generation Modal */}
      <GenerationModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        isLoading={isGeneratingSolution}
        solution={generatedSolution}
      />

      <button onClick={onBack} className="flex items-center text-gray-400 hover:text-white mb-6 transition-colors">
        <ArrowLeft size={18} className="mr-2" /> Retour au menu
      </button>

      {/* Header */}
      <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-8 gap-6">
        <div>
          <h1 className="text-3xl font-serif font-bold text-white mb-2">{new URL(data.url).hostname}</h1>
          <p className="text-gray-400 text-sm">Analysé le {new Date(data.timestamp).toLocaleDateString()} à {new Date(data.timestamp).toLocaleTimeString()}</p>
        </div>
        <div className="flex gap-3">
          <button 
            onClick={handleShare}
            disabled={processingAction !== 'idle'}
            className={`px-4 py-2 rounded-lg bg-white/5 hover:bg-white/10 text-white flex items-center gap-2 text-sm border border-white/10 transition-colors relative ${processingAction !== 'idle' ? 'opacity-50 cursor-not-allowed' : ''}`}
          >
            {processingAction === 'share' ? <Loader2 size={16} className="animate-spin" /> : <Share2 size={16} />} 
            {processingAction === 'share' ? 'Préparation...' : (showShareToast ? 'Copié !' : 'Partager')}
            {showShareToast && (
                <span className="absolute -top-1 -right-1 flex h-3 w-3">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-primary opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-3 w-3 bg-primary"></span>
                </span>
            )}
          </button>
          <button 
            onClick={handleDownloadPDF}
            disabled={processingAction !== 'idle'}
            className={`px-4 py-2 rounded-lg bg-primary text-black font-medium flex items-center gap-2 text-sm transition-colors ${processingAction !== 'idle' ? 'opacity-70 cursor-wait' : 'hover:bg-primaryDark'}`}
          >
            {processingAction === 'download' ? <Loader2 size={16} className="animate-spin" /> : <Download size={16} />}
            {processingAction === 'download' ? 'Génération...' : 'Rapport PDF'}
          </button>
        </div>
      </div>

      {/* Toast Notification */}
      {showShareToast && (
        <div className="fixed bottom-10 left-1/2 transform -translate-x-1/2 bg-white text-black px-6 py-3 rounded-full shadow-2xl z-50 flex items-center gap-2 animate-bounce-short">
           <Check size={18} className="text-primary" />
           <span className="font-medium">Lien copié dans le presse-papier !</span>
        </div>
      )}

      {/* Tabs */}
      <div className="border-b border-white/10 mb-8 overflow-x-auto">
        <div className="flex space-x-8">
          {tabs.map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`pb-4 px-2 text-sm font-medium whitespace-nowrap transition-colors relative ${
                activeTab === tab.id ? 'text-primary' : 'text-gray-400 hover:text-white'
              }`}
            >
              {tab.label}
              {activeTab === tab.id && (
                <div className="absolute bottom-0 left-0 w-full h-0.5 bg-primary rounded-t-full"></div>
              )}
            </button>
          ))}
        </div>
      </div>

      {/* Content */}
      <div className="min-h-[500px]">
        {activeTab === 'overview' && (
          <div className="grid md:grid-cols-12 gap-8">
            {/* Colonne Gauche : Score */}
            <div className="md:col-span-4 space-y-6">
              <div className="glass-panel p-8 rounded-2xl flex flex-col items-center text-center">
                <h3 className="text-lg font-medium text-gray-300 mb-6">Score AEO Global</h3>
                <ScoreRing score={data.globalScore} size={180} />
                <p className="mt-6 text-sm text-gray-400 leading-relaxed">
                  Votre score indique une probabilité de {data.aiCitation.probability}% d'être cité comme source autoritaire par les modèles d'IA générative.
                </p>
              </div>

              <div className="glass-panel p-6 rounded-xl">
                <h3 className="font-medium text-white mb-4">Points forts</h3>
                <ul className="space-y-3">
                  {categoryScores
                    .flatMap(c => c.items.filter(i => i.status === 'success'))
                    .slice(0, 3)
                    .map((item, i) => (
                      <li key={i} className="flex items-start gap-2 text-sm text-gray-300">
                        <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 mt-1.5 shrink-0" />
                        {item.message}
                      </li>
                    ))}
                </ul>
              </div>
            </div>

            {/* Colonne Droite : Pédagogie & Graphique */}
            <div className="md:col-span-8 space-y-6">

              {/* Carte Explicative */}
              <div className="glass-panel p-8 rounded-2xl border border-white/10 relative overflow-hidden">
                <div className="absolute top-0 right-0 p-8 opacity-5">
                  <Zap size={120} />
                </div>
                <div className="flex items-start gap-4 mb-4 relative z-10">
                  <div className="w-10 h-10 rounded-lg bg-primary/20 flex items-center justify-center text-primary shrink-0">
                    <Info size={24} />
                  </div>
                  <div>
                    <h3 className="text-xl font-serif font-bold text-white mb-2">
                      Pourquoi l'Optimisation AEO est vitale ?
                    </h3>
                    <p className="text-gray-300 leading-relaxed text-sm">
                      L'indexation classique (SEO) ne suffit plus. Aujourd'hui, <strong>40% des recherches ne génèrent plus de clics</strong> car les utilisateurs lisent directement la réponse de l'IA.
                      Les modèles comme GPT-4 ou Gemini fonctionnent selon la logique du <em>"Winner Takes All"</em> : seule la source considérée comme la plus fiable est citée. 
                      <br /><br />
                      Si vous n'êtes pas structuré pour être "compris" par ces algorithmes, vous êtes invisible pour cette nouvelle audience.
                    </p>
                  </div>
                </div>
              </div>

              {/* Graphique de Projection */}
              <div className="glass-panel p-6 rounded-xl border border-white/10">
                <div className="flex justify-between items-center mb-6">
                   <h4 className="font-medium text-gray-200 flex items-center gap-2">
                      <TrendingUp size={18} className="text-primary" />
                      Impact de l'Annuaire sur la Visibilité
                   </h4>
                   <span className="text-xs text-gray-500 bg-white/5 px-2 py-1 rounded">Projection 6 mois</span>
                </div>

                <div className="relative h-64 w-full bg-gradient-to-b from-transparent to-white/5 rounded-lg p-4 border border-white/5">
                  {/* Grid Lines */}
                  <div className="absolute inset-0 flex flex-col justify-between p-4 opacity-20">
                    <div className="w-full h-px bg-white"></div>
                    <div className="w-full h-px bg-white"></div>
                    <div className="w-full h-px bg-white"></div>
                    <div className="w-full h-px bg-white"></div>
                    <div className="w-full h-px bg-white"></div>
                  </div>

                  {/* SVG Chart */}
                  <svg className="w-full h-full overflow-visible" preserveAspectRatio="none">
                    <defs>
                      <linearGradient id="gradientOptimized" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="0%" stopColor="#10b981" stopOpacity="0.5" />
                        <stop offset="100%" stopColor="#10b981" stopOpacity="0" />
                      </linearGradient>
                    </defs>

                    {/* Standard Curve (Low Growth) */}
                    <path 
                      d="M0,200 C100,195 300,190 600,180" 
                      fill="none" 
                      stroke="#6b7280" 
                      strokeWidth="2" 
                      strokeDasharray="5,5"
                    />
                    <text x="580" y="170" fill="#6b7280" fontSize="10" textAnchor="end">Standard SEO</text>

                    {/* Optimized Curve (High Growth) */}
                    <path 
                      d="M0,200 C100,190 200,150 600,40" 
                      fill="url(#gradientOptimized)" 
                      stroke="#10b981" 
                      strokeWidth="3" 
                      className="drop-shadow-[0_0_10px_rgba(16,185,129,0.5)]"
                    />

                    {/* Points of Interest */}
                    <circle cx="0" cy="200" r="4" fill="#10b981" />
                    <circle cx="200" cy="150" r="4" fill="#10b981" />
                    <circle cx="600" cy="40" r="4" fill="#10b981" />

                    {/* Labels */}
                    <text x="10" y="220" fill="#9ca3af" fontSize="10">Aujourd'hui</text>

                    {/* Activation Annotation */}
                    <g transform="translate(200, 130)">
                       <rect x="-60" y="-20" width="120" height="20" rx="4" fill="#064e3b" stroke="#10b981" strokeWidth="1" />
                       <text x="0" y="-6" fill="white" fontSize="10" textAnchor="middle" fontWeight="bold">Intégration Annuaire</text>
                       <line x1="0" y1="0" x2="0" y2="20" stroke="#10b981" strokeDasharray="2,2" />
