             <p className="text-sm text-gray-400">{new Date(data.timestamp).toLocaleDateString()}</p>
          </div>
        </div>

        <div className="mb-12 flex items-center gap-10 bg-white/5 p-8 rounded-2xl border border-white/10">
          <div className="flex flex-col items-center">
            <ScoreRing score={data.globalScore} size={150} noAnimation />
            <span className="mt-2 font-medium text-lg">Score Global</span>
          </div>
          <div className="flex-1">
             <h3 className="text-xl font-serif mb-2">Résumé de performance</h3>
             <p className="text-gray-300 text-sm mb-4 leading-relaxed">
               L'analyse de votre contenu révèle une probabilité de <strong>{data.aiCitation.probability}%</strong> d'être utilisé comme source par les IA. 
               Il y a {data.recommendations.filter(r => r.priority === 'critical').length} points critiques à corriger immédiatement.
             </p>
             <div className="grid grid-cols-2 gap-4">
                {categoryScores.slice(0, 4).map((cat, i) => (
                   <div key={i} className="flex justify-between items-center bg-black/30 p-2 rounded px-3">
                      <span className="text-sm text-gray-400">{cat.name}</span>
                      <span className={`font-bold ${cat.score >= 80 ? 'text-emerald-400' : cat.score >= 50 ? 'text-amber-400' : 'text-red-400'}`}>{cat.score}</span>
                   </div>
                ))}
             </div>
          </div>
        </div>

        <div className="mb-10">
           <h3 className="text-2xl font-serif mb-6 pb-2 border-b border-white/10">Détail des Catégories</h3>
           <div className="grid grid-cols-2 gap-6">
              {categoryScores.map((cat, i) => (
                 <div key={i} className="bg-white/5 p-4 rounded-xl border border-white/10">
                    <div className="flex justify-between items-center mb-3">
                       <h4 className="font-medium text-gray-200">{cat.name}</h4>
                       <span className={`font-bold ${cat.score >= 80 ? 'text-emerald-400' : 'text-amber-400'}`}>{cat.score}/100</span>
                    </div>
                    <ul className="space-y-2">
                       {cat.items.slice(0, 3).map((item, idx) => (
                          <li key={idx} className="text-xs text-gray-400 flex items-start gap-2">
                             <div className={`w-1.5 h-1.5 rounded-full mt-1 shrink-0 ${item.status === 'success' ? 'bg-emerald-500' : item.status === 'warning' ? 'bg-amber-500' : 'bg-red-500'}`} />
                             {item.message}
                          </li>
                       ))}
                    </ul>
                 </div>
              ))}
           </div>
        </div>

        <div>
           <h3 className="text-2xl font-serif mb-6 pb-2 border-b border-white/10">Plan d'action prioritaire</h3>
           <div className="space-y-4">
              {data.recommendations.map((rec, i) => (
                 <div key={i} className="bg-white/5 p-5 rounded-xl border border-white/10">
                    <div className="flex justify-between mb-2">
                       <span className="text-xs font-bold uppercase tracking-wider text-primary">{rec.category}</span>
                       <span className="text-xs bg-white/10 px-2 py-0.5 rounded text-gray-300">{rec.priority}</span>
                    </div>
                    <h4 className="text-lg font-medium mb-2">{rec.title}</h4>
                    <p className="text-sm text-gray-400 mb-3">{rec.description}</p>
                    <div className="bg-black/30 p-3 rounded border-l-2 border-primary">
                       <p className="text-sm font-medium">Action : <span className="text-gray-300 font-normal">{rec.action}</span></p>
                    </div>
                 </div>
              ))}
           </div>
        </div>

        <div className="mt-12 text-center text-xs text-gray-500 border-t border-white/10 pt-6">
           Rapport généré automatiquement par CitedBy.ai - La plateforme d'optimisation pour l'ère générative.
        </div>
      </div>
    </div>
  );
};

export default Results;

