import React, { useState } from 'react';
import { Shield, Zap, Globe, Check, Lock, ChevronRight, Server, Sparkles, CreditCard, Loader2, RefreshCw, ArrowLeft } from 'lucide-react';

interface DirectoryProps {
  onBack: () => void;
}

const Directory: React.FC<DirectoryProps> = ({ onBack }) => {
  const [step, setStep] = useState<'intro' | 'form' | 'payment' | 'success'>('intro');
  const [isProcessing, setIsProcessing] = useState(false);
  const [formData, setFormData] = useState({
    companyName: '',
    website: '',
    description: '',
    industry: '',
    competitors: ''
  });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleFormSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setStep('payment');
  };

  const handlePayment = async () => {
    setIsProcessing(true);
    // Simulation du processus de paiement et d'enregistrement
    await new Promise(resolve => setTimeout(resolve, 3000));
    setIsProcessing(false);
    setStep('success');
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-10 animate-in fade-in duration-500 min-h-[80vh]">

      <button onClick={onBack} className="flex items-center text-gray-400 hover:text-white mb-6 transition-colors">
        <ArrowLeft size={18} className="mr-2" /> Retour au menu
      </button>

      {/* HEADER SECTION */}
      <div className="text-center mb-16 space-y-4">
        <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-primary/10 border border-primary/20 text-primary text-xs font-medium uppercase tracking-wider">
          <Globe size={12} />
          <span>Réseau de Confiance IA</span>
        </div>
        <h1 className="text-4xl md:text-5xl font-serif font-bold text-white">
          Annuaire & Certification AEO

