import React, { useState } from 'react';
import { Sparkles, TrendingUp, Target, Award, MousePointerClick, ArrowRight, ScanLine, Code2, Globe2, Search, Loader2, Shield, BookOpen, Lock, Zap } from 'lucide-react';
import { User } from '../types';
import ScoreRing from '../components/ScoreRing';

interface HomeProps {
  onNavigate: (view: string) => void;
  user: User | null;
}

// Deterministic score simulation based on URL
const simulateEEATScore = (brandName: string, url: string) => {
  let hash = 0;
  const seed = brandName + url;
  for (let i = 0; i < seed.length; i++) {
    hash = ((hash << 5) - hash) + seed.charCodeAt(i);
    hash = hash & hash;
  }
  const base = Math.abs(hash % 40) + 35; // Score between 35-75
  return {
    global: base,
    experience: Math.min(100, base + (Math.abs(hash >> 4) % 20) - 10),
    expertise: Math.min(100, base + (Math.abs(hash >> 8) % 20) - 10),
    authority: Math.min(100, base + (Math.abs(hash >> 12) % 20) - 10),
    trust: Math.min(100, base + (Math.abs(hash >> 16) % 20) - 10),
  };
};

const Home: React.FC<HomeProps> = ({ onNavigate, user }) => {
  const [freeScoreBrand, setFreeScoreBrand] = useState('');
  const [freeScoreUrl, setFreeScoreUrl] = useState('');
  const [isCalculating, setIsCalculating] = useState(false);
  const [freeScoreResult, setFreeScoreResult] = useState<ReturnType<typeof simulateEEATScore> | null>(null);

  const handleStartAnalysis = () => {
    if (user) {
      onNavigate('analyze');
    } else {
      onNavigate('login');
    }
  };

  const handleFreeScore = async () => {
    if (!freeScoreBrand || !freeScoreUrl) return;
    setIsCalculating(true);
    // Simulate processing
    await new Promise(resolve => setTimeout(resolve, 2000));
    const result = simulateEEATScore(freeScoreBrand, freeScoreUrl);
    setFreeScoreResult(result);
    setIsCalculating(false);
  };

