            </div>

            <div className="bg-white/5 p-6 rounded-xl border border-white/5 hover:border-primary/20 transition-colors">
              <div className="flex items-start gap-4">
                <div className="w-10 h-10 rounded-full bg-amber-500/20 flex items-center justify-center text-amber-400 shrink-0">
                  <Award size={20} />
