                  className="px-6 py-3 bg-primary text-black font-bold rounded-xl hover:brightness-110 transition-all flex items-center gap-2 disabled:opacity-50"
                >
                  {isAuditing ? <Loader2 size={16} className="animate-spin" /> : <Search size={16} />}
                  {isAuditing ? 'Analyse...' : 'Auditer'}
                </button>
              </div>
            </div>

            {/* Audit Results */}
            {auditResult && (
              <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
                {/* Score Cards */}
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                  {(['experience', 'expertise', 'authority', 'trust'] as const).map(pillar => (
                    <div key={pillar} className="glass-panel p-5 rounded-xl border border-white/10 text-center">
                      <p className="text-xs uppercase tracking-wider mb-2" style={{ color: PILLAR_COLORS[pillar] }}>
                        {PILLAR_LABELS[pillar]}
                      </p>
